<?php
namespace Tests\Feature; use App\Models\User; use Illuminate\Foundation\Testing\RefreshDatabase; use Illuminate\Support\Facades\Http; use Tests\TestCase;
class SteamAuthTest extends TestCase { use RefreshDatabase; public function test_steam_redirect_uses_openid():void{$this->get('/auth/steam')->assertRedirectContains('steamcommunity.com/openid/login');} public function test_verified_steam_identity_creates_and_logs_in_player():void{config(['services.steam.api_key'=>'test-key']);Http::fake(['steamcommunity.com/openid/login'=>Http::response("is_valid:true\n"),'api.steampowered.com/*'=>Http::response(['response'=>['players'=>[['steamid'=>'76561198000000000','personaname'=>'NEXUS Player','profileurl'=>'https://steamcommunity.com/id/nexus','avatarfull'=>'https://cdn.example/avatar.jpg']]]])]);$query=['openid_claimed_id'=>'https://steamcommunity.com/openid/id/76561198000000000','openid_mode'=>'id_res'];$this->get(route('auth.steam.callback',$query))->assertRedirect();$this->assertAuthenticated();$this->assertDatabaseHas('users',['steam_id'=>'76561198000000000','name'=>'NEXUS Player']);$this->get(route('profile.show',User::first()))->assertOk()->assertSee('NEXUS Player');} }
